(function(){const sliderWrap=document.querySelector('.full-auto-slider');const track=document.querySelector('.full-auto-slider-track');if(!sliderWrap||!track)return;let slides=track.querySelectorAll('.full-auto-slide');const total=slides.length;if(total<=1)return;let index=0;let timer=null;let startX=0;let currentX=0;let dragging=false;let moved=false;track.appendChild(slides[0].cloneNode(true));function width(){return sliderWrap.clientWidth}function move(px,animate){track.style.transition=animate?'transform 0.8s ease':'none';track.style.transform='translate3d('+px+'px,0,0)'}function updateText(){slides.forEach(function(slide){slide.classList.remove('show-text')});if(index===total-1){slides[index].classList.remove('show-text');void slides[index].offsetWidth;slides[index].classList.add('show-text')}}function go(i){index=i;move(-index*width(),true);updateText();if(index===total){setTimeout(function(){index=0;move(0,false);updateText()},800)}}function next(){go(index+1)}function prev(){if(index===0){index=total;move(-index*width(),false);setTimeout(function(){go(total-1)},20)}else{go(index-1)}}function startAuto(){stopAuto();timer=setInterval(next,4000)}function stopAuto(){if(timer)clearInterval(timer)}function start(e){stopAuto();dragging=true;moved=false;startX=e.type==='mousedown'?e.clientX:e.touches[0].clientX;currentX=startX;track.style.transition='none'}function moveDrag(e){if(!dragging)return;currentX=e.type==='mousemove'?e.clientX:e.touches[0].clientX;const diff=currentX-startX;if(Math.abs(diff)>5){moved=true}move(-index*width()+diff,false)}function end(){if(!dragging)return;dragging=false;const diff=currentX-startX;if(diff<-60){next()}else if(diff>60){prev()}else{go(index)}setTimeout(function(){moved=false},200);startAuto()}sliderWrap.addEventListener('click',function(e){if(moved){e.preventDefault();e.stopPropagation();return false}},true);sliderWrap.addEventListener('mousedown',start);window.addEventListener('mousemove',moveDrag);window.addEventListener('mouseup',end);sliderWrap.addEventListener('touchstart',start,{passive:true});sliderWrap.addEventListener('touchmove',moveDrag,{passive:true});sliderWrap.addEventListener('touchend',end);window.addEventListener('resize',function(){move(-index*width(),false)});startAuto()})();